const IMGS = {
  a1: "data:image/jpeg;base64,",
  a2: "data:image/jpeg;base64,",
  a3: "data:image/jpeg;base64,",
  a4: "data:image/jpeg;base64,",
  a5: "data:image/jpeg;base64,",
  a7: "data:image/jpeg;base64,",
  a8: "data:image/jpeg;base64,",
  a9: "data:image/jpeg;base64,",
  a10: "data:image/jpeg;base64,",
  a11: "data:image/jpeg;base64,",
};

document.addEventListener("DOMContentLoaded", function() {
  document.querySelectorAll("img[data-src]").forEach(function(img) {
    var key = img.getAttribute("data-src");
    if(IMGS[key]) img.src = IMGS[key];
  });
});
